(function($){var settings=[];var setting;var modal;$.fn.uploader=function(options){setting=$.extend({id:$(this).attr("id"),endpoint:"",title:"Import Dialog...",acceptedFiles:/(csv|ms-excel)$/i,fileSizeLimit:5e6,success:function(e,data){return},fail:function(e,data){return},errorAttachment:function(errors){return},params:{}},options);var foundSettings=$.grep(settings,(function(e){return e.id==setting.id}));if(foundSettings.length>0){setting=foundSettings[0]}else{settings.push(setting)}modal=$(this);modal.modal({backdrop:"static",keyboard:false});modal.on("shown.bs.modal",(function(){modal.find(".modal-title").html(setting.title)}));modal.find(".fileupload").fileupload({add:function(e,data){var uploadErrors=[];var acceptFileTypes=setting.acceptedFiles;if(data.originalFiles[0]["type"].length&&!acceptFileTypes.test(data.originalFiles[0]["type"])){uploadErrors.push("Not an accepted file type")}if(data.originalFiles[0]["size"].length&&data.originalFiles[0]["size"]>setting.fileSizeLimit){uploadErrors.push("Filesize is too big")}if(uploadErrors.length>0){setting.errorAttachment(uploadErrors)}else{$(".btn-import-ok").addClass("busy");data.submit()}},url:setting.endpoint,dataType:"json",done:function(e,data){$(".btn-import-ok").removeClass("busy");$(".btn-import-cancel").addClass("hidden");setting.success(e,data)},progressall:function(e,data){var progress=parseInt(data.loaded/data.total*100,10);$("#progress .progress-bar").css("width",progress+"%")}}).prop("disabled",!$.support.fileInput).parent().addClass($.support.fileInput?undefined:"disabled").bind("fileuploadfail",(function(e,data){modal.find(".btn-import-ok").removeClass("busy");setting.fail(e,data)})).bind("fileuploadprocessstart",(function(e,data){console.log(data.files.valid)}));modal.on("hidden.bs.modal",(function(){$(".lbl-import-message").css("color","#0b8e2e");$(".lbl-import-message").html("")}));modal.find(".btn-import-ok").click((function(){location.reload()}));return modal}})(jQuery);